changeSet.sql:
-- 1) Insérer d'abord les nouveaux test_result (avec sort_order 1..4) pour le test 494. INSERT INTO clinlims.test_result (id, test_id, tst_rslt_type, value, sort_order, is_active, lastupdated) SELECT nextval('clinlims.test_result_seq'), 494, 'D', d.id::varchar, CASE d.dict_entry WHEN 'I' THEN 1 WHEN 'II' THEN 2 WHEN 'III' THEN 3 WHEN 'IV' THEN 4 END, TRUE, NOW() FROM clinlims.dictionary d JOIN clinlims.dictionary_category dc ON dc.id = d.dictionary_category_id WHERE dc.name = 'Bacteriology Flora Type' AND d.dict_entry IN ('I','II','III','IV');
-- 2) Migrer chaque result.value ET result.test_result_id en une passe par mapping : -- 1627 ("1") -> "I", 1628 ("2") -> "II", 1598 ("3") -> "III", 1692 (">=4") -> "IV" WITH mapping AS ( SELECT old_val::varchar AS old_val, entry FROM ( VALUES ('1627','I'), ('1628','II'), ('1598','III'), ('1692','IV') ) AS v(old_val, entry) ), new_test_results AS ( SELECT tr.id AS new_tr_id, tr.value AS dict_id FROM clinlims.test_result tr JOIN clinlims.dictionary d ON d.id::varchar = tr.value JOIN clinlims.dictionary_category dc ON dc.id = d.dictionary_category_id WHERE tr.test_id = 494 AND dc.name = 'Bacteriology Flora Type' ) UPDATE clinlims.result r SET value = ntr.dict_id, test_result_id = ntr.new_tr_id::numeric FROM clinlims.analysis a, mapping m, clinlims.dictionary d, new_test_results ntr WHERE r.analysis_id = a.id AND a.test_id = 494 AND r.value = m.old_val AND d.dict_entry = m.entry AND d.dictionary_category_id = (SELECT id FROM clinlims.dictionary_category WHERE name = 'Bacteriology Flora Type' LIMIT 1) AND ntr.dict_id = d.id::varchar;
-- 3) Supprimer les anciens test_result du test 494 (plus de FK résiduelle). DELETE FROM clinlims.test_result WHERE test_id = 494 AND value IN ('1627','1628','1598','1692');
